Here's a test class demonstrating modern MSTest async patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    // MSTest v3+ natively supports async Task test methods.
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_OnSuccess()
    {
        var handler = new MockHandler("hello", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("hello", result);
    }

    // [Timeout] cancels the test's CancellationToken after N ms.
    // Access it via TestContext.CancellationTokenSource.Token
    // and pass it through to your async code.
    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_RespectsTimeout(TestContext testContext)
    {
        var handler = new MockHandler("ok", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        var token = testContext.CancellationTokenSource.Token;
        var result = await fetcher.FetchAsync("https://example.com", token);

        Assert.AreEqual("ok", result);
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnCancel()
    {
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel

        var handler = new MockHandler("x", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    public async Task FetchAsync_ThrowsOnServerError()
    {
        var handler = new MockHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    // Minimal stub — no mocking library needed.
    private sealed class MockHandler(string content, HttpStatusCode status)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(status)
            {
                Content = new StringContent(content)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns shown:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task`, not `void` |
| **Timeouts** | `[Timeout(ms)]` — MSTest auto-cancels the token |
| **Access the token** | `TestContext.CancellationTokenSource.Token` (MSTest v3+) |
| **Assert throws** | `Assert.ThrowsExactlyAsync<T>()` for async exceptions |
| **Mock HttpClient** | Custom `HttpMessageHandler` — no external library needed |

> Requires **MSTest v3.8+** for `ThrowsExactlyAsync` and the `TestContext` cancellation token parameter. Use packages `MSTest` ≥ 3.8 or the individual `MSTest.TestFramework` + `MSTest.TestAdapter`.
